debug_info.goal:
n : ℕ
Γ : ↑{Γ | Finite ↥Γ}
⊢ LocallyCompactSpace (MulAction.orbitRel.Quotient (↥↑Γ) (Eucl n))

proof:
-- Since the quotient map is an open surjection and Eucl n is locally compact, the quotient space is locally compact.
have h_open_surjection : IsOpenQuotientMap (Quotient.mk (MulAction.orbitRel (Γ : Subgroup ((Eucl n) ≃ₗ[ℝ] (Eucl n))) (Eucl n))) := by
  constructor;
  · exact Quotient.mk_surjective;
  · exact { isOpen_preimage := fun s a ↦ a };
  · intro U hU;
    -- Since the quotient map is open, the image of an open set under the quotient map is open.
    have h_open : IsOpen (Quotient.mk (MulAction.orbitRel (Γ : Subgroup ((Eucl n) ≃ₗ[ℝ] (Eucl n))) (Eucl n)) ⁻¹' (Quotient.mk (MulAction.orbitRel (Γ : Subgroup ((Eucl n) ≃ₗ[ℝ] (Eucl n))) (Eucl n)) '' U)) := by
      simp_all +decide [ Set.preimage, Quotient.mk', MulAction.orbitRel ];
      simp +decide [ Quotient.eq ];
      simp +decide [ MulAction.orbit ];
      simp +decide [ Set.setOf_exists ];
      refine' isOpen_iUnion fun i => _;
      by_cases hi : i ∈ Γ.val <;> simp +decide [ hi, hU ];
      exact hU.preimage ( by exact i.continuous_of_finiteDimensional );
    exact isOpen_mk.mpr h_open;
convert h_open_surjection.locallyCompactSpace

